import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.ByAj6Cie.js";const h=JSON.parse('{"title":"Emergency Stop","description":"","frontmatter":{},"headers":[],"relativePath":"en/safety/emergency-stop.md","filePath":"en/safety/emergency-stop.md"}'),o={name:"en/safety/emergency-stop.md"};function r(n,e,l,c,p,d){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="emergency-stop" tabindex="-1">Emergency Stop <a class="header-anchor" href="#emergency-stop" aria-label="Permalink to &quot;Emergency Stop&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>An emergency stop is a safety function designed to immediately stop a machine or process in a hazardous situation.</p><p>It is typically implemented using a dedicated device that, when activated, removes energy or brings the system to a safe state as quickly as possible.</p><p>Emergency stops are a critical part of industrial safety systems.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of an emergency stop is to reduce risk during abnormal or dangerous conditions.</p><p>It is used to:</p><ul><li>Stop hazardous motion or processes</li><li>Protect personnel from injury</li><li>Prevent equipment damage</li><li>Provide a quick and accessible safety action</li></ul><p>It is intended for emergency situations, not for normal operation.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>An emergency stop system interrupts control or power circuits to stop the system safely.</p><h3 id="activation-device" tabindex="-1">Activation Device <a class="header-anchor" href="#activation-device" aria-label="Permalink to &quot;Activation Device&quot;">​</a></h3><p>The emergency stop is usually a push button.</p><ul><li>Red button with a yellow background</li><li>Latching mechanism that stays engaged when pressed</li></ul><p>It must be easily accessible to operators.</p><h3 id="safety-circuit" tabindex="-1">Safety Circuit <a class="header-anchor" href="#safety-circuit" aria-label="Permalink to &quot;Safety Circuit&quot;">​</a></h3><p>The emergency stop is connected to a safety circuit.</p><ul><li>Typically uses normally closed contacts</li><li>Opening the circuit triggers the stop</li></ul><p>This ensures fail safe behavior.</p><h3 id="stop-action" tabindex="-1">Stop Action <a class="header-anchor" href="#stop-action" aria-label="Permalink to &quot;Stop Action&quot;">​</a></h3><p>When activated:</p><ul><li>Power to actuators is removed or controlled safely</li><li>Motion is stopped as quickly as possible</li><li>System enters a safe state</li></ul><p>The exact stop method depends on the system design.</p><h3 id="reset-function" tabindex="-1">Reset Function <a class="header-anchor" href="#reset-function" aria-label="Permalink to &quot;Reset Function&quot;">​</a></h3><p>After activation:</p><ul><li>The device must be manually reset</li><li>Restart requires a separate deliberate action</li></ul><p>This prevents automatic restart after a fault.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Emergency stops are used in all industrial systems.</p><p>Typical applications include:</p><ul><li>Machinery and production lines</li><li>Motor driven equipment</li><li>Automated systems</li><li>Process plants</li></ul><p>They are required wherever hazards are present.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><p>Emergency stops must be easily accessible and clearly visible.</p><p>The stop function must be reliable and fail safe.</p><p>The stopping method must match the type of hazard.</p><p>Integration with safety systems must be properly designed.</p><p>Standards and regulations must be followed.</p><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><p>A common mistake is using emergency stop for normal stopping. It should only be used in emergencies.</p><p>Do not bypass or disable emergency stop circuits.</p><p>Ensure proper placement so operators can reach it quickly.</p><p>Test emergency stop functionality regularly.</p><p>Verify that the system remains in a safe state after activation.</p>',45)])])}const m=t(o,[["render",r]]);export{h as __pageData,m as default};
